import{_ as a,o,c as t,a2 as i}from"./chunks/framework.OWFDNrRT.js";const m=JSON.parse('{"title":"Community","description":"","frontmatter":{},"headers":[],"relativePath":"community.md","filePath":"community.md","lastUpdated":1773460793000}'),r={name:"community.md"};function s(n,e,l,u,h,c){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h1><p>Welcome to the DINOForge community! This is the hub for connecting with other modders, sharing your work, and helping shape the future of DINO modding.</p><h2 id="github-discussions" tabindex="-1">GitHub Discussions <a class="header-anchor" href="#github-discussions" aria-label="Permalink to &quot;GitHub Discussions&quot;">​</a></h2><p>Our primary community space is <a href="https://github.com/KooshaPari/Dino/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a>. Here you can:</p><h3 id="ask-questions" tabindex="-1">Ask Questions <a class="header-anchor" href="#ask-questions" aria-label="Permalink to &quot;Ask Questions&quot;">​</a></h3><p>Have a question about DINOForge or DINO modding? Post in <a href="https://github.com/KooshaPari/Dino/discussions/categories/q-a" target="_blank" rel="noreferrer">Q&amp;A</a>. The community and maintainers are here to help.</p><h3 id="showcase-your-mods" tabindex="-1">Showcase Your Mods <a class="header-anchor" href="#showcase-your-mods" aria-label="Permalink to &quot;Showcase Your Mods&quot;">​</a></h3><p>Share your completed mod packs in <a href="https://github.com/KooshaPari/Dino/discussions/categories/pack-showcase" target="_blank" rel="noreferrer">Pack Showcase</a>. Include:</p><ul><li>Pack name and version</li><li>Download link or repository URL</li><li>A description of what it does</li><li>Screenshots or video clips (optional)</li></ul><p>This is the best way to get exposure for your work and inspire other modders.</p><h3 id="share-ideas" tabindex="-1">Share Ideas <a class="header-anchor" href="#share-ideas" aria-label="Permalink to &quot;Share Ideas&quot;">​</a></h3><p>Have a feature request or improvement idea? Post in <a href="https://github.com/KooshaPari/Dino/discussions/categories/ideas" target="_blank" rel="noreferrer">Ideas</a>. Tell us:</p><ul><li>What you want to build or improve</li><li>Which area it affects (SDK, Runtime, Tooling, Docs, Community, etc.)</li><li>Why it would be valuable</li></ul><p>Community votes and maintainer feedback help us prioritize the roadmap.</p><h3 id="stay-updated" tabindex="-1">Stay Updated <a class="header-anchor" href="#stay-updated" aria-label="Permalink to &quot;Stay Updated&quot;">​</a></h3><p>Follow <a href="https://github.com/KooshaPari/Dino/discussions/categories/announcements" target="_blank" rel="noreferrer">Announcements</a> for official updates about releases, breaking changes, and platform milestones.</p><h2 id="reporting-issues" tabindex="-1">Reporting Issues <a class="header-anchor" href="#reporting-issues" aria-label="Permalink to &quot;Reporting Issues&quot;">​</a></h2><p>Found a bug or critical issue? Please report it on <a href="https://github.com/KooshaPari/Dino/issues" target="_blank" rel="noreferrer">GitHub Issues</a> with as much detail as possible:</p><ul><li>What you were trying to do</li><li>What happened</li><li>What you expected to happen</li><li>Steps to reproduce</li><li>Your environment (Windows/Linux, .NET version, etc.)</li></ul><p>We have templates to help guide your report.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Want to contribute code, documentation, or tooling? See <a href="https://github.com/KooshaPari/Dino/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> for:</p><ul><li>How to set up a development environment</li><li>Code style and commit conventions</li><li>Pull request process</li><li>Testing requirements</li></ul><h2 id="community-guidelines" tabindex="-1">Community Guidelines <a class="header-anchor" href="#community-guidelines" aria-label="Permalink to &quot;Community Guidelines&quot;">​</a></h2><p>Please be respectful and constructive in all interactions. We follow the <a href="https://github.com/KooshaPari/Dino/blob/main/CODE_OF_CONDUCT.md" target="_blank" rel="noreferrer">Contributor Covenant Code of Conduct</a>. In brief:</p><ul><li><strong>Be inclusive</strong> - Welcome all skill levels and backgrounds</li><li><strong>Be helpful</strong> - Share knowledge generously</li><li><strong>Be respectful</strong> - Disagree constructively</li><li><strong>Be on-topic</strong> - Keep discussions focused on DINOForge and DINO modding</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>New to DINO modding? Check out our <a href="./guide/getting-started">Getting Started Guide</a> for a complete walkthrough.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong><a href="/Dino/">Documentation</a></strong> - Full reference for DINOForge APIs, pack authoring, and warfare mechanics</li><li><strong><a href="./packs">Pack Registry</a></strong> - Official content packs and community templates</li><li><strong><a href="./roadmap/">Roadmap</a></strong> - Future features and milestones</li><li><strong><a href="./concepts/architecture">Architecture Guide</a></strong> - Deep dive into DINOForge design</li></ul><hr><p>Have fun modding! If you have questions about the community, reach out to the maintainers in Discussions.</p>',32)])])}const p=a(r,[["render",s]]);export{m as __pageData,p as default};
